  ('aboriginal-c5fb3965-moex-00138', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '未成年人未經法定代理人同意拋棄繼承，其效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00139', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '刑法第 134 條規定：「公務員假借職務上之權力、機會或方法，以故意犯本章以外各罪者，加重其刑至二 分之一。但因公務員之身分已特別規定其刑者，不在此限。」下列何種情形，甲應依此規定加重其刑？', '["甲與乙都服務於某市政府刑事警察局，甲聚餐酒後與乙因口角起爭執，毆傷乙", "甲為員警，侵占其於執行職務時所扣押之物", "甲為檢察官，將自己承辦案件中屬偵查不公開之事項洩漏給記者", "甲為派出所警察，利用職務上之機會得知乙之行動電話號碼，而撥打電話恐嚇乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00140', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依刑事訴訟法之規定，被告聲請具保停止羈押，下列何者，法院得駁回其聲請？', '["被告現罹疾病，非保外治療顯難痊癒者", "被告懷胎5月以上或生產後2月未滿者", "被告所犯最重本刑為3年以下有期徒刑、拘役或專科罰金之罪，且非累犯或有犯罪之習慣者", "被告回家探望臨終之至親"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00141', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何者不屬於詢問犯罪嫌疑人應先告知之事項？', '["可以拒絕接受詢問", "得保持緘默，無須違背自己之意思而為陳述", "得選任辯護人。如為低收入戶、中低收入戶、原住民或其他依法令得請求法律扶助者，得請求之", "得請求調查有利之證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00142', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '依我國刑事訴訟法規定，被告之自白，必須具備任意性及真實性，始得作為證據。被告於下列何種情況下 之自白，具備任意性？', '["司法警察以若不認罪，將請求檢察官羈押等語，促使被告認罪", "司法警察以每個人都可能犯錯，犯了錯應該要勇於承擔等語，鼓勵被告認罪", "司法警察以被告的配偶亦被逮捕，如被告承擔其事，即可將其配偶釋放等語，促使被告認罪", "司法警察從下午不斷勸說、溝通到深夜，促使被告認罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00143', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列何人依法可以獨立為被告或犯罪嫌疑人選任辯護人？', '["老師", "社工人員", "祖父", "已訂婚之未婚妻"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00144', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於貪污治罪條例之減刑要件，何者正確？', '["於偵審中自白，即應減輕其刑", "於事實審法院辯論終結前繳交全部犯罪所得，即應減輕其刑", "供出共犯因而查獲，即應減輕其刑", "情節輕微，而其犯罪所得在新臺幣5萬元以下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00145', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '甲在海邊戲水時，發現海中有人溺水，乃未經所有權人乙之同意，破壞乙之倉庫門鎖而取其浮板、泳圈， 往溺水之人方向投擲。甲之行為，根據下列何者得阻卻違法？', '["正當防衛", "緊急避難", "得被害人承諾", "自助行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00146', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '下列關於刑法「減刑」或「不罰」之敘述，何者正確？', '["業務上之正當行為稱為「正當防衛」，僅得「減輕其刑」", "未滿14歲人之行為僅得「減輕其刑」", "滿80歲人之行為「不罰」", "瘖啞人之行為得「減輕其刑」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL),
  ('aboriginal-c5fb3965-moex-00147', 'aboriginal-c5fb3965', 'aboriginal-c5fb3965-moex-113-55d283b0', 'sub-aboriginal-c5fb3965-03', NULL, 'single_choice', '關於刑法第130條所規定之公務員廢弛職務釀成災害罪，下列敘述何者正確？', '["本條為過失純正不作為犯之規定", "本條為不純正不作為犯之規定", "本條為過失犯之規定", "本條為故意犯之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:05+00:00", "source_pdf_sha1": "6dad68724e66", "answer_pdf_sha1": "c40383ac46cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "603", "s": "0611", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "戶政"}'::jsonb, NULL)
